@@ -80,13 +80,18 @@ public partial class MessageFormatter {
 			if (!_placeholderValues.TryGetValue(key, out var value))
 				return m.Value; // No placeholder / value

+			// Escape braces in the value's string representation so that they
+			// cannot be misinterpreted as placeholders if the result is processed
+			// again (e.g., by string.Format).
+			var stringValue = value?.ToString()?.Replace("{", "{{").Replace("}", "}}") ?? string.Empty;
+
 			var format = m.Groups[2].Success // Format specified?
 				? $"{{0:{m.Groups[2].Value}}}"
 				: null;

 			return format == null
 				? value?.ToString()
-				: string.Format(format, value);
+				: string.Format(format, stringValue);
 		});
 	}
